export function resolveImportLocale(context) {
  return context?.locale?.resolved === 'zh-CN' ? 'zh-CN' : 'en'
}

export function tImport(context, key) {
  const locale = resolveImportLocale(context)
  return messages[locale][key] ?? messages.en[key] ?? key
}

export function formatImport(context, key, replacements = {}) {
  return Object.entries(replacements).reduce(
    (message, [token, value]) => message.replaceAll(`{${token}}`, String(value)),
    tImport(context, key),
  )
}
